  group('overloadMult — fixture parity', () {
    /// The Dart calculator's `overloadMult` is band-agnostic — band
    /// matching is the repository's job (it looks up
    /// `exercise_peak_loads_by_rep_range` keyed by `(user, exercise,
    /// rep_band)` and only passes the prior if there's a same-band
    /// record). Mirror that here: derive the rep band from
    /// current + prior reps and pass null priors when they differ.
    String repBand(int reps) {
      if (reps <= 4) return 'heavy';
      if (reps <= 7) return 'strength';
      if (reps <= 12) return 'hypertrophy';
      return 'endurance';
    }

    test('every fixture case matches', () {
      final cases = fixtures['overload_mult'] as List<dynamic>;
      for (final raw in cases) {
        final c = raw as Map<String, dynamic>;
        final w = (c['weight_kg'] as num).toDouble();
        final r = c['reps'] as int;
        final priorW = c['prior_weight_kg'] == null
            ? null
            : (c['prior_weight_kg'] as num).toDouble();
        final priorR = c['prior_reps'] as int?;
        final expected = (c['overload_mult'] as num).toDouble();
        // Cross-band prior → null at the repository boundary; Python
        // sim's helper returns 1.0 in that case (band-keyed lookup miss).
        final crossBand = priorR != null && repBand(r) != repBand(priorR);
        expect(
          XpCalculator.overloadMult(
            weightKg: w,
            reps: r,
            priorWeight: crossBand ? null : priorW,
            priorReps: crossBand ? null : priorR,
          ),
          closeTo(expected, _eps),
          reason:
              '[${c['name']}] overloadMult(w=$w, r=$r, '
              'prior=($priorW, $priorR), crossBand=$crossBand)',
        );
      }
    });

    test('canonical pins — new weight PR → 1.15, volume PR → 1.10, '
        'modest → 1.05, no change → 1.00', () {
      // New weight PR
      expect(
        XpCalculator.overloadMult(
          weightKg: 85,
          reps: 5,
          priorWeight: 80,
          priorReps: 5,
        ),
        1.15,
      );
      // Volume PR at same load
      expect(
        XpCalculator.overloadMult(
          weightKg: 80,
          reps: 8,
          priorWeight: 80,
          priorReps: 5,
        ),
        1.10,
      );
      // Reps up + weight down
      expect(
        XpCalculator.overloadMult(
          weightKg: 75,
          reps: 8,
          priorWeight: 80,
          priorReps: 5,
        ),
        1.05,
      );
      // No change
      expect(
        XpCalculator.overloadMult(
          weightKg: 80,
          reps: 5,
          priorWeight: 80,
          priorReps: 5,
        ),
        1.0,
      );
      // No prior
      expect(XpCalculator.overloadMult(weightKg: 80, reps: 5), 1.0);
    });
  });

