  // ---------------------------------------------------------------------------
  // Phase 29 v2 — full 11-multiplier chain (set_xp_v2 fixture)
  //
  // 94 cases. Tolerance is 1e-4 absolute per the brief — the cumulative
  // chain compounds float rounding more than the component-level tests.
  // ---------------------------------------------------------------------------
  group('computeSetXp — Phase 29 v2 set_xp_v2 fixture parity', () {
    const v2Eps = 1e-4;

    test('every set_xp_v2 case matches within $v2Eps absolute', () {
      final cases = fixtures['set_xp_v2'] as List<dynamic>;
      expect(cases.length, 94, reason: 'expected 94 set_xp_v2 oracle rows');

      var failed = 0;
      var firstFailureMsg = '';

      for (final raw in cases) {
        final c = raw as Map<String, dynamic>;
        final inputs = c['inputs'] as Map<String, dynamic>;
        final components = c['components'] as Map<String, dynamic>;

        final exercise = inputs['exercise'] as String;
        final weight = (inputs['weight_kg'] as num).toDouble();
        final reps = inputs['reps'] as int;
        final peak = (inputs['peak_load'] as num).toDouble();
        final sv = (inputs['session_volume_prior'] as num).toDouble();
        final wv = (inputs['weekly_volume_prior'] as num).toDouble();
        final diff = (inputs['difficulty_mult'] as num).toDouble();
        final bw = (inputs['bodyweight_kg'] as num).toDouble();
        final female = inputs['gender_female'] as bool;
        final ranks = (inputs['current_ranks'] as Map<String, dynamic>).map(
          (k, v) => MapEntry(k, (v as num).toInt()),
        );
        final dominantPart = inputs['dominant_part'] as String;
        final currentRank = ranks[dominantPart]?.toDouble() ?? 1.0;
        final nf = inputs['near_failure'] as bool;
        final target = inputs['target_reps'] as int?;
        final bpSessionCount = inputs['bp_session_count'] as int;
        final usesBw = inputs['uses_bodyweight_load'] as bool;
        final bwRatio = inputs['bodyweight_load_ratio'] == null
            ? null
            : (inputs['bodyweight_load_ratio'] as num).toDouble();

        // Phase 29 v2: the Dart calculator is bodyweight-agnostic. The
        // caller pre-converts entered_weight → effective_load. For
        // bodyweight exercises, that's `entered + bw × ratio`. For
        // non-BW, that's just entered.
        final effLoad = usesBw ? weight + bw * (bwRatio ?? 1.0) : weight;

        // Reconstruct the prior best for overload_mult — the fixture
        // stores `best_by_band_prior` as a 2-list of [(exercise, band),
        // (prior_w, prior_r)] when there is one.
        double? priorW;
        int? priorR;
        final priorRaw = inputs['best_by_band_prior'];
        if (priorRaw != null) {
          // JSON encodes the tuple as a 2-element list:
          // [[exercise_key, band_key], [prior_w, prior_r]]
          final priorList = priorRaw as List<dynamic>;
          final priorTuple = priorList[1] as List<dynamic>;
          priorW = (priorTuple[0] as num).toDouble();
          priorR = (priorTuple[1] as num).toInt();
        }

        // Compute implied tier independently — matches the fixture's
        // expected value (also stored at components.lift_implied_tier).
        final tier = impliedTier(
          exercise: exercise,
          weightKg: weight,
          reps: reps,
          bodyweightKg: bw,
          gender: female ? LiftGender.female : LiftGender.male,
        );

        // Phase 29 v2 chain produces per-(set, body-part) XP, not a
        // single per-set total. The Python sim's `compute_set_xp` runs
        // the per-bp inner loop where each body part sees its OWN
        // novelty_count and weekly_count. The fixture seeds only the
        // dominant body part's session_volume / weekly_volume
        // (`session_volume_seed_bp`); every other body part starts at
        // 0/0 → novelty_mult = 1.0, cap_mult = 1.0 for those.
        //
        // For parity we iterate the attribution map and call the
        // calculator once per body part with the correct per-bp
        // session/weekly volume.
        final seedBp = inputs['session_volume_seed_bp'] as String;
        final awardedPerBp = (c['awarded_per_bp'] as Map<String, dynamic>).map(
          (k, v) => MapEntry(k, (v as num).toDouble()),
        );
        final attribution = (inputs['attribution'] as Map<String, dynamic>).map(
          (k, v) => MapEntry(k, (v as num).toDouble()),
        );

        var allMatch = true;
        SetXpComponents? lastResult;
        for (final entry in attribution.entries) {
          final bp = entry.key;
          final share = entry.value;
          // Only the seed body part carries the seeded prior; every
          // other body part starts fresh in this synthetic fixture.
          final perBpSv = (bp == seedBp) ? sv : 0.0;
          final perBpWv = (bp == seedBp) ? wv : 0.0;

          final result = XpCalculator.computeSetXp(
            weightKg: effLoad,
            reps: reps,
            peakLoad: peak,
            sessionVolumeForBodyPart: perBpSv,
            weeklyVolumeForBodyPart: perBpWv,
            difficultyMult: diff,
            impliedTier: tier,
            currentRank: currentRank,
            priorBandWeight: priorW,
            priorBandReps: priorR,
            sessionsThisWeekForBodyPart: bpSessionCount,
            nearFailure: nf,
            targetReps: target,
          );
          lastResult = result;

          final dartAward = result.setXp * share;
          final pyAward = awardedPerBp[bp] ?? 0.0;
          if ((dartAward - pyAward).abs() > v2Eps) {
            allMatch = false;
            if (firstFailureMsg.isEmpty) {
              firstFailureMsg =
                  '[${c['name']}] bp=$bp '
                  'dart=$dartAward py=$pyAward '
                  'delta=${(dartAward - pyAward).abs()} '
                  '(set_xp=${result.setXp})';
            }
          }
        }

        // Also pin individual component fields so divergence reports a
        // specific multiplier rather than just the total. Use the last
        // computed result; per-bp differs only in novelty + cap.
        final expectedTier = (components['lift_implied_tier'] as num)
            .toDouble();
        if (lastResult != null &&
            (lastResult.impliedTier - expectedTier).abs() > _eps) {
          failed++;
          if (firstFailureMsg.isEmpty) {
            firstFailureMsg =
                '[${c['name']}] implied_tier dart='
                '${lastResult.impliedTier} py=$expectedTier';
          }
        }
        if (!allMatch) failed++;
      }

      expect(
        failed,
        0,
        reason:
            'Phase 29 v2 parity failed for $failed/94 cases. '
            'First failure: $firstFailureMsg',
      );
    });
  });

